<template>
  <v-row justify="center">
    <v-dialog
      :model-value="dialog"
      transition="dialog-bottom-transition"
      fullscreen
    >
      <v-card class="mx-auto card-table" width="100%"
        ><v-toolbar dark color="#624fc6" class="mb-10">
          <v-btn
            icon
            fab
            color="#ffffff"
            x-small
            @click="$emit('popClose')"
            class="mr-1"
          >
            <Icon
              class="icon_download"
              icon="ic:outline-close"
              color="#ffffff"
              width="25"
            />
          </v-btn>

          <v-toolbar-title class="mx-auto d-flex justify-center pl-14">
            <h4 style="font-family: 'Cairo', sans-serif">عناصر الفاتورة</h4>
          </v-toolbar-title>
        </v-toolbar>

        <v-card class="card mx-auto" width="80%">
          <v-data-table-server
            :headers="headers"
            :items="items"
            hide-default-footer
            fixed-header
            height="720"
            :mobile-breakpoint="0"
          >
            <template v-slot:item="{ item }">
              <tr>
                <td class="text-center font-weight-black">
                  <h4>{{ item.barcode }}</h4>
                </td>

                <td class="text-center font-weight-black">
                  <h4>{{ item.product_name }}</h4>
                </td>

                <td class="text-center font-weight-black">
                  <v-swatches
                    v-model="item.color"
                    :disabled="true"
                  ></v-swatches>
                </td>

                <td class="text-center font-weight-black">
                  <h4>{{ item.size }}</h4>
                </td>

                <td class="text-center font-weight-black">
                  <h4>{{ item.quantity }}</h4>
                </td>
                <td class="text-center font-weight-black">
                  <h4>{{ item.returned_quantity }}</h4>
                </td>

                <td class="text-center font-weight-black">
                  <h4>
                    {{
                      $filters.formatNumber(
                        item.price *
                          (item.quantity - (item.returned_quantity || 0))
                      )
                    }}
                    د.ع
                  </h4>
                </td>

                <td class="text-center font-weight-black">
                  <v-tooltip location="bottom" interactive>
                    <template v-slot:activator="{ props }">
                      <v-btn
                        icon
                        x-small
                        v-bind="props"
                        variant="text"
                        base-color="#EF6C00"
                        :disabled="item.returned_quantity === item.quantity"
                        @click="popRetrieveItems(item)"
                        :loading="loading && item.id === sale_item_id"
                      >
                        <Icon
                          icon="fluent:clock-bill-24-filled"
                          color="#EF6C00"
                          width="32"
                        />
                        <template v-slot:loader>
                          <span class="custom-loader">
                            <v-icon color="#EF6C00">mdi-cached</v-icon>
                          </span>
                        </template>
                      </v-btn>
                    </template>
                    <span>استرجاع</span>
                  </v-tooltip>
                </td>
              </tr>
            </template>
          </v-data-table-server>
        </v-card>
      </v-card>
    </v-dialog>
    <PopRetrieveItems
      :dialog="dialog_retrieve_items"
      :maxQuantity="max_quantity_retrieve"
      @retrieveQuantity="retrieveQuantity"
      @popClose="dialog_retrieve_items = false"
    />
  </v-row>
</template>
<script setup>
import { useSalesStore } from "@/stores/sales";
import { ref, computed, defineEmits } from "vue";
import PopRetrieveItems from "@/components/sales/PopRetrieveItems.vue";

const salesStore = useSalesStore();
const quantity = ref(null);
const sale_item_id = ref(null);
const max_quantity_retrieve = ref(1);
const dialog_retrieve_items = ref(false);

const emit = defineEmits(["itemUpdated"]);
defineProps({
  dialog: {
    type: Boolean,
    default: false,
  },
  items: {
    type: Array,
    required: true,
  },
});

const loading = computed(() => salesStore.retrieve_loading);

const headers = [
  {
    title: "باركود",
    value: "barcode",
    align: "center",
    width: "190px",
    headerProps: { class: "secondary white--text text-body-1" },
  },
  {
    title: "المنتج",
    value: "name",
    align: "center",
    width: "190px",
    headerProps: { class: "secondary white--text text-body-1" },
  },
  {
    title: "اللون",
    value: "color",
    align: "center",
    width: "130px",
    headerProps: { class: "secondary white--text text-body-1" },
  },
  {
    title: "القياس",
    value: "size",
    align: "center",
    width: "170px",
    headerProps: { class: "secondary white--text text-body-1" },
  },
  {
    title: "الكمية",
    value: "quantity",
    align: "center",
    width: "150px",
    headerProps: { class: "secondary white--text text-body-1" },
  },
  {
    title: "الكمية المسترجعة",
    value: "quantity",
    align: "center",
    width: "170px",
    headerProps: { class: "secondary white--text text-body-1" },
  },

  {
    title: "السعر",
    value: "price",
    align: "center",
    width: "190px",
    headerProps: { class: "secondary white--text text-body-1" },
  },
  {
    title: "العمليات",
    value: "operations",
    align: "center",
    width: "190px",
    headerProps: { class: "secondary white--text text-body-1" },
  },
];

function popRetrieveItems(item) {
  sale_item_id.value = item.id;
  max_quantity_retrieve.value = item.quantity;
  dialog_retrieve_items.value = true;
}

function retrieveQuantity(retrieve_quantity) {
  quantity.value = retrieve_quantity;
  retrieve();
}

const retrieve = async () => {
  let data = {
    sale_item_id: sale_item_id.value,
    quantity: quantity.value,
  };

  try {
    const response = await salesStore.retrieve_item(data);
    emit("itemUpdated", response.data.result[0]);
  } catch (e) {
    console.error("Error in store", e);
  }
};
</script>
<style scoped>
.card {
  box-shadow: 0px 0px 0px 0px !important;
  border-radius: 25px !important;
  border: 1px solid #cbccce;
}
</style>
