import { defineStore } from "pinia";
import axios from "axios";
import { useSnackbarStore } from "@/stores/snackbar";
import { server } from "@/config";

export const useUserStore = defineStore("user", {
  state: () => ({
    loading_login: false,
    token: localStorage.getItem("token"),
    name: localStorage.getItem("name"),
  }),

  actions: {
    addUser(user) {
      this.users.push(user);
    },

    async login(data) {
      this.loading_login = true;
      try {
        const response = await axios.post(`${server}/api/login`, data, {
          headers: {
            "Content-Type": "application/json",
          },
          method: "POST",
        });

        const token = response.data.token;
        this.loading_login = false;

        axios.defaults.headers.common["Authorization"] = `Bearer ${token}`;
        localStorage.setItem("token", token);
        localStorage.setItem("name", response.data.result[0].name);

        this.name = response.data.result[0].name;
        this.token = token;

        return response;
      } catch (error) {
        const snackbar = useSnackbarStore();

        const errorData = error.response?.data;
        const message =
          [errorData?.message, ...Object.values(errorData?.errors || {}).flat()]
            .filter(Boolean)
            .join("\n") || "حدث خطأ غير متوقع";

        snackbar.showMessage({
          color: "#B71C1C",
          icon: "ri:close-circle-fill",
          text: message,
        });

        this.loading_login = false;

        throw error;
      }
    },
  },

  getters: {
    loggedIn: (state) => {
      return state.token !== null && state.token !== undefined;
    },
  },
});
